SELECT S.COMPANIA, 
  S.ANO,  
  (SUM(S.REG_CONTRACT + S.MODIF_REG_CONT + S.REG_NO_CONTRACT + S.MODIF_REG_NOCONT)) TOTALCOMPROMETIDO,   
  SUM(CASE WHEN P.NATURALEZA='D' THEN S.APROPIACION_DEBITO-S.APROPIACION_CREDITO ELSE S.APROPIACION_CREDITO-S.APROPIACION_DEBITO END) APROPIADOINICIAL,   
  SUM(CASE WHEN P.NATURALEZA='D' THEN S.APROPIACION_DEBITO-S.APROPIACION_CREDITO ELSE S.APROPIACION_CREDITO-S.APROPIACION_DEBITO END) + SUM(S.ADICION) + SUM(S.REDUCCION) + SUM(CASE WHEN P.NATURALEZA='D' THEN S.APLAZAM_DEBITO-S.APLAZAM_CREDITO ELSE S.APLAZAM_CREDITO-S.APLAZAM_DEBITO END) + SUM(CASE WHEN P.NATURALEZA='D' THEN S.TRASLADO_DEBITO-S.TRASLADO_CREDITO ELSE S.TRASLADO_CREDITO-S.TRASLADO_DEBITO END) APRDEFINITIVA,   
  SUM(CASE WHEN P.NATURALEZA='D' THEN S.APROPIACION_DEBITO-S.APROPIACION_CREDITO ELSE S.APROPIACION_CREDITO-S.APROPIACION_DEBITO END) + SUM(S.ADICION) + SUM(S.REDUCCION) + SUM(CASE WHEN P.NATURALEZA='D' THEN S.APLAZAM_DEBITO-S.APLAZAM_CREDITO ELSE S.APLAZAM_CREDITO-S.APLAZAM_DEBITO END) + SUM(CASE WHEN P.NATURALEZA='D' THEN S.TRASLADO_DEBITO-S.TRASLADO_CREDITO ELSE S.TRASLADO_CREDITO-S.TRASLADO_DEBITO END) + SUM(CASE WHEN P.NATURALEZA='D' THEN S.APLAZAM_DEBITO-S.APLAZAM_CREDITO ELSE S.APLAZAM_CREDITO-S.APLAZAM_DEBITO END) - SUM(S.DISPONIBILIDAD) + SUM(S.REINTEGRO) SALDODISPONIBLE 
FROM BP_RUBRO_INVERSION  R INNER JOIN   
      (V_PLAN_PRESUPUESTAL  P INNER JOIN  V_SALDO_PLAN_PPTAL S ON P.COMPANIA = S.COMPANIA 
                                                          AND P.ANO = S.ANO 
                                                          AND P.ID = S.ID)   
      ON R.COMPANIA = P.COMPANIA 
      AND R.RUBRO = P.ID 
      AND R.VIGENCIA = P.ANO 
WHERE R.COMPANIA=s$compania$s 
  AND R.VIGENCIA BETWEEN s$anioInicial$s AND s$anioFinal$s  
GROUP BY S.COMPANIA, S.ANO, S.ID, P.NATURALEZA 
ORDER BY S.ANO ASC
